var expansionArray=["expanded","collapsed"];var visibilityArray=["show","hide"];var leafString="leaf";var lastNodeString="LastNode";function addClass(b,a){if(!classExists(b,a)){b.className+=b.className?" "+a:a}}function removeClass(b,a){var c=b.className.match(" "+a)?" "+a:a;b.className=b.className.replace(c,"")}function classExists(b,a){return new RegExp("\\b"+a+"\\b").test(b.className)}function removeString(d,c){var a=d;var b=d.indexOf(c);if(b>=0){a=d.substring(0,b)}return a}function stopPropagation(a){if(window.event&&window.event.cancelBubble!==null){window.event.cancelBubble=true}else{a.stopPropagation()}}function isClassExpanded(a){currentClassName=a.className;if(currentClassName.indexOf(expansionArray[1])>=0){return false}return true}function handleNodeExpansion(b,a,d,h){stopPropagation(a);var i=document.getElementById(d);if(isLeaf(i)){return}var g=isClassExpanded(i)?0:1;var j=expansionArray[1-g];var c=expansionArray[g];handleIcons(h,j);var e=i.className;var f=e.indexOf(lastNodeString)>0?true:false;if(f){j=j+lastNodeString;c=c+lastNodeString}removeClass(i,c);addClass(i,j);handleChildMenuIfExists(i,g)}function handleChildMenuIfExists(a,b){var c=a.getElementsByTagName("ul");if(c.length<=0){return}var d=c[0];if(classExists(d,visibilityArray[b])){removeClass(d,visibilityArray[b])}addClass(d,visibilityArray[1-b])}function handleIcons(c,a){var b=document.getElementById(c);if(b==null){return}if(isLeaf(b)){return}var d=b.className;removeClass(b,d);addClass(b,a+"Icon")}function isLeaf(a){if(a.className.indexOf(leafString)>=0){return true}return false};